   187→	ret := map[string][]string{}
   188→	for k, v := range extra {
   189→		ret[k] = []string(v)
   190→	}
   191→
   192→	return ret
   193→}
   194→
   195→// AuthorizationAttributesFrom takes a spec and returns the proper authz attributes to check it.
   196→func AuthorizationAttributesFrom(spec authorizationapi.SubjectAccessReviewSpec) authorizer.AttributesRecord {
   197→	userToCheck := &user.DefaultInfo{
   198→		Name:   spec.User,
   199→		Groups: spec.Groups,
   200→		UID:    spec.UID,
   201→		Extra:  convertToUserInfoExtra(spec.Extra),
   202→	}
   203→
   204→	var authorizationAttributes authorizer.AttributesRecord
   205→	if spec.ResourceAttributes != nil {
   206→		authorizationAttributes = ResourceAttributesFrom(userToCheck, *spec.ResourceAttributes)
   207→	} else {
   208→		authorizationAttributes = NonResourceAttributesFrom(userToCheck, *spec.NonResourceAttributes)
   209→	}
   210→
   211→	return authorizationAttributes
   212→}
   213→
   214→// matchAllVersionIfEmpty returns a "*" if the version is unspecified
   215→func matchAllVersionIfEmpty(version string) string {
   216→	if len(version) == 0 {
   217→		return "*"
   218→	}
   219→	return version
   220→}
   221→
   222→// BuildEvaluationError constructs the evaluation error string to include in *SubjectAccessReview status
   223→// based on the authorizer evaluation error and any field and label selector parse errors.
   224→func BuildEvaluationError(evaluationError error, attrs authorizer.AttributesRecord) string {
   225→	var evaluationErrors []string
   226→	if evaluationError != nil {
   227→		evaluationErrors = append(evaluationErrors, evaluationError.Error())
   228→	}
   229→	if reqs, err := attrs.GetFieldSelector(); err != nil {
   230→		if len(reqs) > 0 {
   231→			evaluationErrors = append(evaluationErrors, "spec.resourceAttributes.fieldSelector partially ignored due to parse error")
   232→		} else {
   233→			evaluationErrors = append(evaluationErrors, "spec.resourceAttributes.fieldSelector ignored due to parse error")
   234→		}
   235→	}
   236→	if reqs, err := attrs.GetLabelSelector(); err != nil {
   237→		if len(reqs) > 0 {
   238→			evaluationErrors = append(evaluationErrors, "spec.resourceAttributes.labelSelector partially ignored due to parse error")
   239→		} else {
   240→			evaluationErrors = append(evaluationErrors, "spec.resourceAttributes.labelSelector ignored due to parse error")
   241→		}
   242→	}
   243→	return strings.Join(evaluationErrors, "; ")
   244→}
